namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedAt { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}

namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail);
    Task<Shipment> CreateShipmentAsync(Shipment shipment);
    Task UpdateShipmentStatusAsync(int id, ShipmentStatus status);
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentServiceClient(HttpClient http) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await http.GetFromJsonAsync<Shipment?>($"api/shipments/track/{trackingNumber}");
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        return await http.GetFromJsonAsync<List<Shipment>>($"api/shipments/customer/{Uri.EscapeDataString(customerEmail)}") ?? [];
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var response = await http.PostAsJsonAsync("api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>() ?? shipment;
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{id}/status", status);
        response.EnsureSuccessStatusCode();
    }
}

using System.ComponentModel.DataAnnotations;

namespace ShipmentTracker.Data;

public class ShipmentEntity
{
    public int Id { get; set; }
    [MaxLength(50)]
    public string TrackingNumber { get; set; } = string.Empty;
    [MaxLength(200)]
    public string Origin { get; set; } = string.Empty;
    [MaxLength(200)]
    public string Destination { get; set; } = string.Empty;
    public int Status { get; set; }
    public DateTime CreatedAt { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    [MaxLength(256)]
    public string CustomerEmail { get; set; } = string.Empty;
    [MaxLength(500)]
    public string Description { get; set; } = string.Empty;
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServiceServer(IDbContextFactory<ApplicationDbContext> contextFactory) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        await using var context = await contextFactory.CreateDbContextAsync();
        return await context.Shipments
            .OrderByDescending(s => s.CreatedAt)
            .Select(s => MapToModel(s))
            .ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        await using var context = await contextFactory.CreateDbContextAsync();
        var entity = await context.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity is null ? null : MapToModel(entity);
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        await using var context = await contextFactory.CreateDbContextAsync();
        return await context.Shipments
            .Where(s => s.CustomerEmail == customerEmail)
            .OrderByDescending(s => s.CreatedAt)
            .Select(s => MapToModel(s))
            .ToListAsync();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        await using var context = await contextFactory.CreateDbContextAsync();
        var entity = new ShipmentEntity
        {
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = (int)shipment.Status,
            CreatedAt = DateTime.UtcNow,
            EstimatedDelivery = shipment.EstimatedDelivery,
            CustomerEmail = shipment.CustomerEmail,
            Description = shipment.Description
        };
        context.Shipments.Add(entity);
        await context.SaveChangesAsync();
        shipment.Id = entity.Id;
        shipment.CreatedAt = entity.CreatedAt;
        return shipment;
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        await using var context = await contextFactory.CreateDbContextAsync();
        var entity = await context.Shipments.FindAsync(id);
        if (entity is not null)
        {
            entity.Status = (int)status;
            await context.SaveChangesAsync();
        }
    }

    private static Shipment MapToModel(ShipmentEntity entity) => new()
    {
        Id = entity.Id,
        TrackingNumber = entity.TrackingNumber,
        Origin = entity.Origin,
        Destination = entity.Destination,
        Status = (ShipmentStatus)entity.Status,
        CreatedAt = entity.CreatedAt,
        EstimatedDelivery = entity.EstimatedDelivery,
        CustomerEmail = entity.CustomerEmail,
        Description = entity.Description
    };
}

