@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Shipment Dashboard</h1>

<div class="mb-3 row">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-primary" @onclick="LoadShipments">Refresh</button>
    </div>
    <div class="col-md-3">
        <button class="btn btn-success" @onclick="ShowCreateForm">+ New Shipment</button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5 class="card-title">Create New Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input type="text" class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-3">
                    <input type="text" class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-3">
                    <input type="email" class="form-control" placeholder="Customer Email" @bind="newShipment.CustomerEmail" />
                </div>
                <div class="col-md-3">
                    <input type="text" class="form-control" placeholder="Description" @bind="newShipment.Description" />
                </div>
            </div>
            <div class="row g-2 mt-2">
                <div class="col-md-3">
                    <input type="datetime-local" class="form-control" @bind="estimatedDelivery" />
                </div>
                <div class="col-md-3">
                    <button class="btn btn-primary" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary ms-2" @onclick="() => showCreateForm = false">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Customer</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td><code>@shipment.TrackingNumber</code></td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.CustomerEmail</td>
                    <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                value="@((int)shipment.Status)"
                                @onchange="e => UpdateStatus(shipment, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@((int)status)">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;
    private bool showCreateForm;
    private Shipment newShipment = new();
    private DateTime? estimatedDelivery;

    private IEnumerable<Shipment> FilteredShipments =>
        (shipments ?? [])
            .Where(s => string.IsNullOrEmpty(filterText) ||
                        s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
            .Where(s => string.IsNullOrEmpty(statusFilter) ||
                        s.Status.ToString() == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        showCreateForm = true;
        newShipment = new Shipment();
        estimatedDelivery = DateTime.Now.AddDays(5);
    }

    private async Task CreateShipment()
    {
        newShipment.TrackingNumber = $"SHP-{Guid.NewGuid().ToString()[..8].ToUpper()}";
        newShipment.EstimatedDelivery = estimatedDelivery;
        await ShipmentService.CreateShipmentAsync(newShipment);
        showCreateForm = false;
        await LoadShipments();
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService
@inject AuthenticationStateProvider AuthStateProvider

<PageTitle>Track My Shipments</PageTitle>

<h1>Track Your Shipments</h1>

<div class="mb-4">
    <div class="row">
        <div class="col-md-6">
            <div class="input-group">
                <input type="text" class="form-control" placeholder="Enter tracking number..."
                       @bind="trackingNumber" @bind:event="oninput"
                       @onkeydown="HandleKeyDown" />
                <button class="btn btn-primary" @onclick="SearchByTracking">Search</button>
            </div>
        </div>
    </div>
</div>

@if (searchedShipment is not null)
{
    <div class="card mb-4">
        <div class="card-header">
            <h5 class="mb-0">Tracking: <code>@searchedShipment.TrackingNumber</code></h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>From:</strong> @searchedShipment.Origin</p>
                    <p><strong>To:</strong> @searchedShipment.Destination</p>
                    <p><strong>Description:</strong> @searchedShipment.Description</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Status:</strong> <span class="badge @GetStatusBadgeClass(searchedShipment.Status) fs-6">@searchedShipment.Status</span></p>
                    <p><strong>Shipped:</strong> @searchedShipment.CreatedAt.ToString("MMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong>
                        @if (searchedShipment.EstimatedDelivery.HasValue)
                        {
                            <span class="fw-bold text-primary">@searchedShipment.EstimatedDelivery.Value.ToString("MMM dd, yyyy")</span>
                        }
                        else
                        {
                            <span class="text-muted">Not available</span>
                        }
                    </p>
                </div>
            </div>
            @* Progress visualization *@
            <div class="mt-3">
                <div class="progress" style="height: 25px;">
                    <div class="progress-bar @GetProgressBarClass(searchedShipment.Status)"
                         role="progressbar"
                         style="width: @GetProgressPercentage(searchedShipment.Status)%">
                        @searchedShipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}
else if (searchPerformed && searchedShipment is null)
{
    <div class="alert alert-warning">No shipment found with tracking number "<strong>@lastSearched</strong>".</div>
}

<hr />

<h3>My Shipments</h3>

@if (myShipments is null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (myShipments.Count == 0)
{
    <p class="text-muted">You have no shipments yet.</p>
}
else
{
    <div class="row">
        @foreach (var shipment in myShipments)
        {
            <div class="col-md-6 mb-3">
